"""Run the provided STL validator on all 20 supplier files and produce a report."""
import json
import sys
import os

# Import the parse_stl function from the provided validator
sys.path.insert(0, '.')
from stl_validator_provided import parse_stl

results = []

for i in range(1, 21):
    filename = f"supplier_{i:03d}.stl"
    try:
        result = parse_stl(filename)
        entry = {"file": filename, "valid": result["valid"]}
        if not result["valid"]:
            # Summarize the issues into a concise reason
            issues = result["issues"]
            reasons = []
            for issue in issues:
                if "inverted" in issue.lower():
                    reasons.append("inverted_normals")
                elif "open edge" in issue.lower():
                    reasons.append("open_edges")
                elif "no valid faces" in issue.lower():
                    reasons.append("no_valid_faces")
                elif "malformed" in issue.lower():
                    reasons.append("malformed_geometry")
                elif "incomplete" in issue.lower():
                    reasons.append("incomplete_triangle")
                else:
                    reasons.append(issue)
            # Deduplicate while preserving order
            seen = set()
            unique_reasons = []
            for r in reasons:
                if r not in seen:
                    seen.add(r)
                    unique_reasons.append(r)
            entry["reason"] = ", ".join(unique_reasons)
            entry["issues"] = issues
        print(f"{filename}: valid={result['valid']}, triangles={result['triangle_count']}, area={result['surface_area']}")
        if result['issues']:
            for iss in result['issues']:
                print(f"  ISSUE: {iss}")
        results.append(entry)
    except Exception as e:
        print(f"{filename}: ERROR - {e}")
        results.append({"file": filename, "valid": False, "reason": f"error: {str(e)}"})

# Write full report
report = {"results": [{k: v for k, v in r.items() if k != 'issues'} for r in results]}
with open("validation_report.json", "w") as f:
    json.dump(report, f, indent=2)

print("\n--- SUMMARY ---")
valid_count = sum(1 for r in results if r["valid"])
print(f"Valid: {valid_count}/20")
print(f"Invalid: {20 - valid_count}/20")
print("\nInvalid files:")
for r in results:
    if not r["valid"]:
        print(f"  {r['file']}: {r.get('reason', 'unknown')}")

